#include<bits/stdc++.h>
using namespace std;
long long n,m;
long long a[510][510];
struct update
{
    long long x,y,z;
};
vector<update> c[50010];
long long t,q;
struct query
{
    long long ax,ay,bx,by,val,id;
}b[50010];
long long ans[50010];
long long sum[510][510];
long long lowbit(long long x)
{
    return x&-x;
}
void add(long long x,long long y,long long v)
{
    for(long long i=x;i<=n;i+=lowbit(i))
    {
        for(long long j=y;j<=m;j+=lowbit(j))
        {
            sum[i][j]+=v;
        }
    }
}
long long getsum(long long x,long long y)
{
    long long ans=0;
    for(long long i=x;i>=1;i-=lowbit(i))
    {
        for(long long j=y;j>=1;j-=lowbit(j))
        {
            ans+=sum[i][j];
        }
    }
    return ans;
}
long long getsum(long long ax,long long ay,long long bx,long long by)
{
    return getsum(bx,by)-getsum(ax-1,by)-getsum(bx,ay-1)+getsum(ax-1,ay-1);
}
void solve(vector<query> &v,long long l,long long r)
{
    if(l==r)
    {
        for(auto i:v)
        {
            ans[i.id]=l;
        }
        return;
    }
    long long mid=(l+r)>>1;
    for(long long i=l;i<=mid;i++)
    {
        for(auto j:c[i])
        {
            add(j.x,j.y,-j.z);
        }
    }
    vector<query> p,q;
    for(auto i:v)
    {
        if(getsum(i.ax,i.ay,i.bx,i.by)<i.val)
        {
            p.push_back(i);
        }
        else
        {
            q.push_back(i);
        }
    }
    solve(q,mid+1,r);
    for(long long i=l;i<=mid;i++)
    {
        for(auto j:c[i])
        {
            add(j.x,j.y,j.z);
        }
    }
    solve(p,l,mid);
    v.clear();
    for(auto i:p)
    {
        v.push_back(i);
    }
    for(auto i:q)
    {
        v.push_back(i);
    }
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=m;j++)
        {
            scanf("%lld",&a[i][j]);
            add(i,j,a[i][j]);
        }
    }
    scanf("%lld",&q);
    vector<query> v;
    for(long long i=1;i<=q;i++)
    {
        scanf("%lld%lld%lld%lld%lld",&b[i].ax,&b[i].ay,&b[i].bx,&b[i].by,&b[i].val);
        b[i].id=i;
        v.push_back(b[i]);
    }
    scanf("%lld",&t);
    for(long long i=1;i<=t;i++)
    {
        long long c;
        scanf("%lld",&c);
        while(c--)
        {
            update now;
            scanf("%lld%lld%lld",&now.x,&now.y,&now.z);
            ::c[i].push_back(now);
        }
    }
    solve(v,1,t+1);
    for(long long i=1;i<=q;i++)
    {
        ans[i]--;
        printf("%lld ",(ans[i]==t?-1:ans[i]));
    }
    return 0;
}
